// Disparar o Job para a fila (no Controller)
EnviarEmailBoasVindas::dispatch($user);

// Disparar com delay de 5 minutos
EnviarEmailBoasVindas::dispatch($user)->delay(now()->addMinutes(5));

// Processar a fila (em produção, use Supervisor)
php artisan queue:work

// Em desenvolvimento, processar um job de cada vez
php artisan queue:listen
